export function getRandomQuote() {
  const idx = Math.floor(Math.random() * ALL_QUOTES.length);
  return { text: ALL_QUOTES[idx], category: 'romantic' };
}

export function getDailyQuote(date) {
  const d = date || new Date();
  const seed = d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
  return { text: ALL_QUOTES[seed % ALL_QUOTES.length], category: 'romantic' };
}

export function getDailyMorningQuote(date) {
  const d = date || new Date();
  const seed = d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
  // Pick from first 600 quotes (morning-style)
  return { text: ALL_QUOTES[seed % 600], category: 'morning' };
}

export function getQuoteByCategory(cat) { return getRandomQuote(); }
export function getQuoteByIndex(idx) { return { text: ALL_QUOTES[idx % ALL_QUOTES.length], category: 'romantic' }; }
export function getTotalQuoteCount() { return ALL_QUOTES.length; }
export function getHolidayQuote() { return getRandomQuote(); }
